__global__ void copy_coalesced(const float* __restrict__ in, float* __restrict__ out, int n) {
  int i = (int)blockIdx.x * (int)blockDim.x + (int)threadIdx.x;
  if (i < n) out[i] = in[i];
}

__global__ void saxpy(float a, const float* __restrict__ x, float* __restrict__ y, int n) {
  int tid = (int)blockIdx.x * (int)blockDim.x + (int)threadIdx.x;
  int stride = (int)blockDim.x * (int)gridDim.x;
  for (int i = tid; i < n; i += stride) y[i] = a * x[i] + y[i];
}

__global__ void add_vec4(const float* __restrict__ a, const float* __restrict__ b,
                         float* __restrict__ c, int n) {
  int i4 = (((int)blockIdx.x * (int)blockDim.x) + (int)threadIdx.x) * 4;
  if (i4 + 3 < n) {
    const float4* A = reinterpret_cast<const float4*>(a);
    const float4* B = reinterpret_cast<const float4*>(b);
    float4* C = reinterpret_cast<float4*>(c);
    int idx = i4 / 4;
    float4 va = A[idx];
    float4 vb = B[idx];
    C[idx] = {va.x + vb.x, va.y + vb.y, va.z + vb.z, va.w + vb.w};
  }
}

template<int TILE>
__global__ void gemm_tiled(const float* __restrict__ A, const float* __restrict__ B,
                          float* __restrict__ C, int M, int N, int K) {
  __shared__ float As[TILE][TILE];
  __shared__ float Bs[TILE][TILE];
  int row = (int)blockIdx.y * TILE + (int)threadIdx.y;
  int col = (int)blockIdx.x * TILE + (int)threadIdx.x;
  float acc = 0.0f;
  for (int t = 0; t < K; t += TILE) {
    As[threadIdx.y][threadIdx.x] = (row < M && t + threadIdx.x < K) ? A[row * K + (t + threadIdx.x)] : 0.0f;
    Bs[threadIdx.y][threadIdx.x] = (col < N && t + threadIdx.y < K) ? B[(t + threadIdx.y) * N + col] : 0.0f;
    __syncthreads();
    #pragma unroll
    for (int k = 0; k < TILE; ++k) acc += As[threadIdx.y][k] * Bs[k][threadIdx.x];
    __syncthreads();
  }
  if (row < M && col < N) C[row * N + col] = acc;
}

__device__ __forceinline__ float wave_reduce_sum(float v) {
  for (int offset = warpSize / 2; offset > 0; offset >>= 1) {
    v += __shfl_down(v, offset);
  }
  return v;
}

__global__ void relu_branchless(const float* __restrict__ x, float* __restrict__ y, int n) {
  int i = (int)blockIdx.x * (int)blockDim.x + (int)threadIdx.x;
  if (i < n) {
    float v = x[i];
    y[i] = v > 0.0f ? v : 0.0f;
  }
}

__global__ void idx_fast(const float* __restrict__ in, float* __restrict__ out, int n) {
  int i = (int)blockIdx.x * (int)blockDim.x + (int)threadIdx.x;
  if (i < n) {
    int lane8 = i & 7;   // i % 8
    int group = i >> 3;  // i / 8
    out[i] = in[i] + (float)(lane8 + group);
  }
}

__global__ void pressure_example(const float* __restrict__ x, float* __restrict__ y, int n) {
  int i = (int)blockIdx.x * (int)blockDim.x + (int)threadIdx.x;
  if (i < n) {
    float v = x[i];
    { // limit lifetime of temps
      float t1 = v * 1.1f;
      float t2 = t1 + 2.2f;
      v = t2;
    }
    y[i] = v;
  }
}

